$(function () {

	var $body = $('body');

	//SVGスプライト
	$.ajax({
		type: 'get',
		url: '/wp-content/themes/creo-ru/assets/svg/icons.svg'//ここにパスを入れる（環境に合わせて変更）
	}).done(function(data) {
		var svg = $(data).find('svg');
		$('body').prepend(svg);
	});

	//ページ内スクロール
	$('a[href^="#"]').click(function(){
		var speed = 400;
		var href= $(this).attr("href");
		var target = $(href == "#" || href == "" ? 'html' : href);
		var position = target.offset().top - 91;
		$('body,html').animate({scrollTop:position}, speed, 'swing');
		return false;
	});


	//スクロールしたらクラスを付与
	$(window).scroll(function () {
		if ($(this).scrollTop() > 300) {
			$body.addClass("scroll");
		} else {
			$body.removeClass("scroll");
		}
	});

	//ページトップボタンフッター前で止める
	$(document).ready(function () {
		// $(".fix_cv").hide();
		$(window).on("scroll", function () {
			scrollHeight = $(document).height();
			scrollPosition = $(window).height() + $(window).scrollTop();
			footHeight = $(".wpcf7").innerHeight();
			if (scrollHeight - scrollPosition <= footHeight) {
				$(".fix_cv").addClass("on");
			} else {
				$(".fix_cv").removeClass("on");
			}
		});
	});


		//加盟店の声スライド(スマホのみ)
	var voice_swiper;
	$(window).on('load resize', function(){
		var w = $(window).width();
		if (w <= 768) {
			if (voice_swiper) {
				return;
			} else {
				voice_swiper = new Swiper('.voice_swiper', {
					loop: true,
					// autoplay: {
					// 	delay: 4000,
					// },
					spaceBetween: 19,
					slidesPerView: 1,
					centeredSlides: true,
					pagination: {
						el: '.swiper-pagination',
						clickable: true,
					},
					navigation: {
						nextEl: '.swiper-button-next-1',
						prevEl: '.swiper-button-prev-1',
					}
				});
			}
		} else {
			if (voice_swiper) {
				voice_swiper.destroy();
				voice_swiper = undefined;
			}
		}
	});

$(document).on("click", "#privacy_text", function () {
  document.getElementById("privacy_modal").classList.add("--active");
  document
    .getElementById("privacy_overlay")
    .addEventListener("touchmove", disableScroll, { passive: false });
  document
    .getElementById("privacy_overlay")
    .addEventListener("mousewheel", disableScroll, { passive: false });
});

$(document).on("click", "#privacy_overlay", function () {
  document.getElementById("privacy_modal").classList.remove("--active");
});

$(document).on("click", ".close-btn", function () {
  document.getElementById("privacy_modal").classList.remove("--active");
});

function disableScroll(event) {
  event.preventDefault();
}

	//フォーム郵便番号
	$('.input_half_button').on('click', function(){
		AjaxZip3.zip2addr( 'your-zip', '', 'your-prefecture', 'your-address' );
		//成功時に実行する処理
		AjaxZip3.onSuccess = function() {
			$('.your-address').focus();
		};
		//失敗時に実行する処理
		AjaxZip3.onFailure = function() {
			alert('郵便番号に該当する住所が見つかりません');
		};
		return false;
	});

	//フェードインで表示（セクション）
	$(window).scroll(function (){
		$('.fadein').each(function(){
			var elemPos = $(this).offset().top;
			var scroll = $(window).scrollTop();
			var windowHeight = $(window).height();
			if (scroll > elemPos - windowHeight + 200){
				$(this).addClass('scrollin');
			}
		});
	});

});